demo.code:
# Базовий try/except
try:
    result = 10 / 0
except ZeroDivisionError:
    print('Помилка: ділення на нуль')

# З параметрами
try:
    numbers = [1, 2, 3]
    print(numbers[10])
except IndexError as e:
    print(f'Помилка: {e}')

# Обробка кількох типів
try:
    value = int('abc')
except ValueError:
    print('Не число')
except TypeError:
    print('Неправильний тип')

